impl Solution { pub fn max_width_ramp(black_n: Vec<i32>) -> i32 { let mut black_s = vec![]; for (black_i, &black_v) in black_n.iter().enumerate() { if black_s.is_empty() || black_v < black_n[*black_s.last().unwrap()] { black_s.push(black_i); } } black_n.iter().enumerate().rev().fold(0, |mut black_max, (black_j, &black_v)| { while !black_s.is_empty() && black_v >= black_n[*black_s.last().unwrap()] { black_max = black_max.max((black_j - black_s.pop().unwrap()) as i32); } black_max }) } }